"use strict";(self.webpackChunkdocu=self.webpackChunkdocu||[]).push([[684],{4241:(e,t,a)=>{a.r(t),a.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>d,frontMatter:()=>s,metadata:()=>n,toc:()=>l});var n=a(1953),i=a(4848),o=a(8453);const s={title:"k/acc manifesto",authors:"grate",tags:["acc"]},r="Criticism of (x)/acc",c={authorsImageUrls:[void 0]},l=[];function h(e){const t={h1:"h1",p:"p",...(0,o.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.p,{children:"Accelerationism is seen as either a hateful, aggressive militant ideology or as a natural forming process - as complexity increases, capacity follows then it\u2019s only natural that things will get quicker. Some argue acc started with marx others argue it started with land I\u2019m of the view marx was the origin and land was the form (though nick land should no longer be taken seriously, he now just boomer posts on twitter, at this point it\u2019s not even worth reading his work directly since it\u2019s explained in other works in a much more accessable form) Marx saw acc as a function of capitalism that could be stopped, overcame. Land saw it as unstoppable so embracing it is all that\u2019s left - since then people have expanded it further - the most fitting analogy is that of a train, we\u2019re sat on a train marxs looks out the window and notices it\u2019s speeding up with no chance of stopping, he looks further down the track and sees the tracks ending, he wants the train to be slowed down and hopefully stopped - land looks out of the window and reaches the conclusion the train will only ever speed up so we should try and speed it up as much as possible to get it over and done with."}),"\n",(0,i.jsx)(t.p,{children:"Extended from this is the idea of \u201cclearing the pit\u201d the train gets so much speed it\u2019s existing momentum at the moment of derailing might keep us going until we either land on another track or until we can build one."}),"\n",(0,i.jsx)(t.p,{children:"One common myth is that accelerationism is right leaning, this was not true of marx and (kind of) wasn\u2019t true of nick land or the CCRU - included in accelerationism is l/acc seeking to reach automated luxery communism, g/acc seeking to abolish the concept of gender, xenofeminism seeking to use capitalism and acc to remove gender inequality to establish true feminism. CCRU was a very left leaning group and most if not all excluding land went on and continued to be incredibly impactful left leaning thinkers, two recognisable cases being sadie plant and mark fisher - claiming acc as right leaning wipes out all of the wokr done and being done by left leaning thinkers - just because right leaning people dominate acc spaces on twitter doesn\u2019t mean they are the ideology, as is mostly the left has allowed the right to claim ownership over some thing that should rightfully belong to the left."}),"\n",(0,i.jsx)(t.p,{children:"This should hopefully give enough of a background into acc that the rest logically follows."}),"\n",(0,i.jsx)(t.p,{children:"The issues with most acc subgenres is they lack coherence, formal value sets and any actual structure - they mostly fall into the catagory of thing/acc with no actual considerations A logical prerequesit (that I\u2019m currently violating) should be to write an outline of your thing/acc before you can put it in your twitter name or bio - watch almost any interview with accelerationists and you\u2019ll see quickly how they\u2019ve never thought about what it actually means."}),"\n",(0,i.jsx)(t.p,{children:"Beff explains eacc to lex"}),"\n",(0,i.jsx)(t.p,{children:"It\u2019s obvious from this clip that beff could explain it in simple language but chooses not to, I agree with feynman if you can\u2019t explain it to a layman you don\u2019t have a good enough grasp on it - watch that entire clip then ask what should an e/accer actually do? it\u2019s laid out a value set but not a formal structure, an interesting note on that vidoe is beff claims d/acc as a fork to e/acc but I don\u2019t know why he beleives this from the opening lines of the d/acc manifesto he explains it\u2019s meant as a response to andreessens techno-optimist manifesto which makes me question if beff has even read it, e/acc is barely mentioned - but this isn\u2019t meant to be focused too much on beff but unfortunately he\u2019s the central figure and most notable in acc spaces right now even though I honest to god do not know if he\u2019s doing anything beyond posting on twitter, he talks like he\u2019s incredibly important but I\u2019ve yet see anyone point to a solid thing he\u2019s done, he\u2019s talked about how vital open source and working in public is to progress but is incredibly evasive about the things he\u2019s doing/working on - I\u2019m not making the claim he\u2019s a liar or a scammer moreso just if it\u2019s impossible to verify if someones doing something it\u2019s concerning - from his use of language in the clip he is knowlegable about accelerationism and seemingly the ideas of deluze and the other one but that\u2019s what makes it even more frustrating right now (x)/acc is going through such a level of decentralisation that it\u2019s fracturing and now the power is distributed among too many nodes and it\u2019s potential for power growth is highly limited due to people aprehension of AI - meanwhile tenents of k/acc continue to grow in the mainstream."}),"\n",(0,i.jsx)(t.h1,{id:"accelerationism-as-natural-process",children:"Accelerationism as natural process"}),"\n",(0,i.jsx)(t.p,{children:"Look at human history and what you see is clear acceleration in all things, humans strive this striving causes creation and from creation comes complexity as complexity increases so does the potential for creation resulting in further complexity this process continues until the blissful or bitter end. But from complexity also comes a much faster rate of progression, of societal values, technology, human understanding, everything. it all requires a threshold level of complexity - this isn\u2019t to say all forms of complexity are important and valuble, organic, inorganic and artifical all exist."}),"\n",(0,i.jsx)(t.p,{children:"This cycle is not just a characteristic of human ambition but a reflection of the fundamental laws of nature and evolution. Just as biological organisms evolve by adapting to their environments in increasingly complex ways, so too does human society evolve by creating and adapting to new technologies and ideas. This evolution is not linear but accelerates as each layer of complexity adds depth and speed to the process. The result is a world where changes that once took centuries now unfold in decades, if not years, reshaping our societies and selves at an unprecedented pace. Through this lens, accelerationism can be seen not merely as a socio-political theory but as an extension of the natural process of evolution, magnified by human consciousness and creativity."}),"\n",(0,i.jsx)(t.p,{children:"The acceleration of this process could lead to a tipping point where human society either adapts to its rapid pace of change or faces significant upheaval. This is where the concept of accelerationism becomes not just an observation but a critical framework for understanding and navigating the future. By embracing and accelerating these changes, rather than resisting them, humanity can harness this natural process for transformation. Through conscious effort and foresight, we have the potential to guide this acceleration in ways that promote sustainability, equality and well-being, seeing complexity not as a challenge but as an opportunity for unprecedented growth and advancement."}),"\n",(0,i.jsx)(t.p,{children:"In essence, the process of complexity highlights the interconnectedness of human innovation with the evolutionary forces of nature. It acknowledges that while the path forward may contain challenges, the same processes that drive complexity and change also hold the keys to our adaptation and flourishing in an ever-accelerating world. Things will get faster regardless of human action - humans just seemingly have the largest capacity to make things go faster but everything from a whale to an ant is making things go faster."}),"\n",(0,i.jsx)(t.p,{children:"As a small note here I want to point out complexity / complicatedness, the design, manufacture and shipping of a toothbrush is highly complex, it\u2019s also not complicated."}),"\n",(0,i.jsx)(t.h1,{id:"what-is-kacc",children:"What is k/acc?"}),"\n",(0,i.jsx)(t.p,{children:"k/acc or knowledge accelerationsim is a fundementally human centric approach to accelerationism - unless it furthers the goal of humans it is not included, an AI that irons clothes is disregarded, an AI that helps people learn is encouraged. k/acc is the belief that human conciousness is both unique and something we cannot replicate (though with sufficiant advancement we may come close), that a core part of that conciousness stems from knowledge and that knowledge in and of itself offers value in all aspects of life - it enables control over yourself, allows the world to be more interesting and almost every issue our species have faced and will face comes down to knowledge (or a lack of). Conflict and a lack of cooperation are no exception - without sufficiant knowledge nothing can be resolved. We are no more than an animal taking rough guesses based on memory and feelings - This has a hard limit on potential and our species overcoming this limit through knowledge is why we\u2019ve come so much further."}),"\n",(0,i.jsx)(t.p,{children:"Underpinning k/acc is the conviction that technological advancements must pivot around enhancing human capabilities and consciousness. Technology should not merely aim to automate tasks but to augment human intellect and creativity, bridging the gap between what is and what could be. In this light, k/acc champions technologies and innovations that empower individuals to navigate, understand, and interact with the world in more profound and impactful ways. The emphasis is on tools that facilitate learning, comprehension, and the application of knowledge in solving real-world problems, thereby enriching human experience and potential. Things like intellectual property and copyright take a backseat to enhancing the ability for people to actualise knowledge (art being a form of applied knowledge)."}),"\n",(0,i.jsx)(t.p,{children:"Central to k/acc is the idea that knowledge is not just power but the very foundation of progress and enlightenment. It is through the acquisition and application of knowledge that humans have the potential to be human. By fostering an environment where knowledge is freely accessed, shared, and applied, k/acc aims to catalyze a global movement towards a more human world. It is a call to action for all of humanity to embrace the pursuit of knowledge, not just as a means to an end, but as an end in itself."}),"\n",(0,i.jsx)(t.p,{children:"In essence, k/acc serves as a manifesto for a future where technology and human intellect converge in a harmonious pursuit of progress and self-actualization. It is a fever dream vision of a world where every individual is empowered to be."}),"\n",(0,i.jsx)(t.h1,{id:"why-kacc-has-to-be-the-first-step",children:"Why k/acc has to be the first step"}),"\n",(0,i.jsx)(t.p,{children:"The imperative that k/acc, be the initial step in the broader accelerationist movement stems from its foundational belief that knowledge underpins all forms of human progress and societal development. This conviction is not just philosophical but practical; before any technological, social, or political acceleration can be effectively pursued, a comprehensive and deeply ingrained understanding of knowledge as both a resource and a capability must be established."}),"\n",(0,i.jsx)(t.p,{children:"Knowledge equips individuals and societies with the ability to make informed decisions. Without a profound and widespread understanding of the world, its complexities, and the potential consequences of our actions, attempts to accelerate in any domain are likely to be misguided, inefficient, or even harmful. True innovation requires a rich substrate of knowledge from which to draw. By prioritizing k/acc, we ensure that creativity and invention are not stifled by ignorance or limited perspectives. A society well-versed in a broad range of disciplines is better equipped to generate breakthroughs that can propel humanity forward in a meaningful way."}),"\n",(0,i.jsx)(t.p,{children:"The acceleration of technology and societal change brings with it a host of ethical dilemmas and moral considerations. This will hamper widespread adoption k/acc allows you to push accelerationism without ever sayign the word."}),"\n",(0,i.jsx)(t.p,{children:"Knowledge accelerationism fosters a sense of community and shared purpose. When individuals recognize the value of knowledge and its role in shaping the future, they are more likely to collaborate and contribute to collective endeavors. This unity is essential for the sustained, coordinated action required to navigate the challenges and opportunities of acceleration."}),"\n",(0,i.jsx)(t.h1,{id:"directive-of-kacc",children:"Directive of k/acc"}),"\n",(0,i.jsx)(t.p,{children:"The primary directive of k/acc, is to actively pursue and facilitate the unrestricted flow and enhancement of knowledge across all spectrums of society. This involves dismantling barriers to information accessibility and leveraging technological innovations to democratize education and intellectual growth. It asserts that every individual should have the opportunity to learn, understand, and contribute to the collective pool of human knowledge, without limitations imposed by socioeconomic status, geography, or institutional gatekeeping."}),"\n",(0,i.jsx)(t.p,{children:"This directive calls for a radical rethinking of educational systems, advocating for a shift from traditional, hierarchical models of instruction to more decentralized, collaborative, and personalized forms of learning. The aim is to cultivate a culture where curiosity and critical thinking are nurtured, allowing for a more adaptable and resilient society"}),"\n",(0,i.jsx)(t.p,{children:"The directive emphasizes the role of technology not just as a tool for disseminating information but as a means to enhance cognitive capabilities and create new forms of knowledge interaction. It envisions a future where augmented reality, virtual spaces, and AI-driven platforms provide immersive and interactive learning experiences, making the acquisition of knowledge a more engaging and effective process."})]})}function d(e={}){const{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(h,{...e})}):h(e)}},8453:(e,t,a)=>{a.d(t,{R:()=>s,x:()=>r});var n=a(6540);const i={},o=n.createContext(i);function s(e){const t=n.useContext(o);return n.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),n.createElement(o.Provider,{value:t},e.children)}},1953:e=>{e.exports=JSON.parse('{"permalink":"/2024/03/15/kacc-manifesto","editUrl":"https://github.com/bippyboppy/bippyboppy.github.io/tree/main/blog/2024-03-15-kacc-manifesto.md","source":"@site/blog/2024-03-15-kacc-manifesto.md","title":"k/acc manifesto","description":"Accelerationism is seen as either a hateful, aggressive militant ideology or as a natural forming process - as complexity increases, capacity follows then it\u2019s only natural that things will get quicker. Some argue acc started with marx others argue it started with land I\u2019m of the view marx was the origin and land was the form (though nick land should no longer be taken seriously, he now just boomer posts on twitter, at this point it\u2019s not even worth reading his work directly since it\u2019s explained in other works in a much more accessable form) Marx saw acc as a function of capitalism that could be stopped, overcame. Land saw it as unstoppable so embracing it is all that\u2019s left - since then people have expanded it further - the most fitting analogy is that of a train, we\u2019re sat on a train marxs looks out the window and notices it\u2019s speeding up with no chance of stopping, he looks further down the track and sees the tracks ending, he wants the train to be slowed down and hopefully stopped - land looks out of the window and reaches the conclusion the train will only ever speed up so we should try and speed it up as much as possible to get it over and done with.","date":"2024-03-15T00:00:00.000Z","tags":[{"inline":false,"label":"Accelerationism","permalink":"/tags/acc","description":"acc"}],"readingTime":10.64,"hasTruncateMarker":true,"authors":[{"name":"Grate","title":"nobody","url":"https://github.com/yangshun","page":{"permalink":"/authors/grate"},"socials":{"github":"https://github.com/bippyboppy"},"imageURL":"https://avatars.githubusercontent.com/u/144010979?v=4","key":"grate"}],"frontMatter":{"title":"k/acc manifesto","authors":"grate","tags":["acc"]},"unlisted":false,"prevItem":{"title":"Pessimism Kills","permalink":"/2024/03/29/pessimism-kills"}}')}}]);